SELECT b.id as equipment_ID, b.Substation_ID as value FROM ies_ms.breaker_b b join ies_ms.feeder_b f on b.feeder_id = f.id join ies_ms.subcontrolarea_b sa on f.subcontrolarea_id = sa.id join ies_ms.company_b c on sa.company_id = c.id WHERE b.id IN
#{equipment_ID}
